/** Рассчитывает начальный номер в соседних номерах страниц
 *  < 1 ... [соседние номера страниц] ... 15 >
 */
const getStart = (newPage, count, siblingCount) => {
    /** Если количество страниц <= 2, то отобразится только начальный номер страницы и конечный,
     * считать соседние страницы не надо ->   < 1 >  или  < 1 2 >
     */
    if (count === 2) {
        return;
    }
    /**
     * Отображаем страницу 2 вместо "...", так как диапазон начинается с 3
     * не красиво:    1 ... [3 4 5] ... 8
     * красиво:       1 [2 3 4 5] ... 8
     */
    if (newPage <= siblingCount + 1) {
        return 2;
    }
    /**
   * Отображаем 2, если начало диапазона рассчитано как 0 или -1.
   * Работает для таких примеров как {siblingCount 4, count: 6},
   где диапазон меньше общего количества на 2 странички или менее
   */
    if (newPage === count) {
        return count - siblingCount - 1 === 1 ? 2 : count - siblingCount - 1;
    }
    /**
   * Если подошли к последним страницам,
   но надо оставить позади страницу для отматывания диапазона назад

   * Если активная страница 5, начнём диапазон со страницы 4, чтобы прокрутить назад -> 1 ... [4 5 6 7] 8
   */
    if (newPage + siblingCount > count) {
        return count - siblingCount - 1;
    }
    /** Начинаем диапазон с текущая страница - 1, чтобы можно было прокрутить диапазон назад */
    if (newPage + 1 === count && newPage !== 2) {
        return newPage - 1;
    }
    /** Центрируем по возможности активнуцю страницу в диапазоне, смещая её ~ на половину диапазона  */
    return newPage - Math.floor(siblingCount / 2);
};
/** Рассчитывает последний номер в соседних номерах страниц
 *  < 1 ... [соседние номера страниц] ... 15 >
 */
const getFinish = (start, newPage, count, siblingCount) => {
    /** Если количество страниц <= 2, то отобразится только начальный номер страницы и конечный,
     * считать соседние страницы не надо ->   < 1 >  или  < 1 2 >
     */
    if (!start) {
        return;
    }
    /** Если находимся в конце, то конец диапазона == предпоследней странице */
    if (count - newPage - 1 < siblingCount) {
        return count - 1;
    }
    /**
     * Так как надо отрисовать 2 страницу, сделаем диапазон на одну страницу шире, чем активаная страница
     * Активаня страница 4  -> 1 [ 2 3 4 5] ... 8
     * */
    if (newPage === siblingCount + 1) {
        return siblingCount + 2;
    }
    /** Если находимся в начале и количество страниц мало,
     * то нарисуем предпоследнюю страницу,
     * иначе нарисуем весь диапазон
     */
    if (newPage < 1 + siblingCount) {
        return start + siblingCount === count ? count - 1 : start + siblingCount;
    }
    /** Весь диапазон*/
    return start + siblingCount - 1;
};

export { getFinish, getStart };
